    string smallestNumber(string pattern) {
        string res = "";
        int num = 1;
        for (char c : pattern) {
            while (res.size() > 0 && res.back() != '0' && (c == 'I' || (c == 'D' && res.back() < '9' && res.back() + 1 < num + '0'))) {
                res += to_string(num);
