            }
            if (res.size() == 0 || res.back() == '0') {
                res += to_string(num);
                num++;
            } else {
                res.back()++;
            }
        }
        while (res.size() > 0 && res.back() != '0') {
            res += to_string(num);
            num++;
        }
        return res;
    }
};

